ON CONFLICT (codigo_fabricante) DO UPDATE SET
  fabricante        = EXCLUDED.fabricante,
  familia           = EXCLUDED.familia,
  grupo             = EXCLUDED.grupo,
  subgrupo          = EXCLUDED.subgrupo,
  descricao_completa = EXCLUDED.descricao_completa,
  categoria_me      = EXCLUDED.categoria_me,
  unidade           = EXCLUDED.unidade,
  ncm               = EXCLUDED.ncm,
  caracteristicas   = EXCLUDED.caracteristicas,
  atualizado_em     = now();

-- Verificação
SELECT categoria_me, COUNT(*) AS qtd
FROM produtos_catalogo
WHERE fabricante = 'Dispan'
GROUP BY categoria_me
ORDER BY categoria_me;
